import React, { useState, useContext } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import '../styles/LoginForm.css';
import { AuthContext } from './AuthContext';

const LoginForm = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [rememberMe, setRememberMe] = useState(false);
  const [error, setError] = useState(''); // Ajouté pour gérer les messages d'erreur
  const navigate = useNavigate();
  const { login } = useContext(AuthContext);
 
  const handleSubmit = async (event) => {
    event.preventDefault();
    // Validation simple côté client
    if (!email || !password) {
      setError('Veuillez entrer un email et un mot de passe.');
      return;
    }

    try {
      const response = await axios.post('https://127.0.0.1:8000/login', {
        email: email,
        password: password,
      
      });
      
      localStorage.setItem('token', response.data.token);
      login();
      navigate('/');
    } catch (error) {
      setError('Erreur de connexion. Veuillez réessayer.'); // Message d'erreur générique
      console.error('Erreur de connexion', error);
    }
  };

  return (
    <div className="login-form-container">
      <form onSubmit={handleSubmit} className="login-form">
        {error && <div className="error-message">{error}</div>} {/* Affichage des erreurs */}
        <div className="form-group">
          <label htmlFor="email">Email</label>
          <input
            type="email" // Type mis à jour pour une validation de formulaire native
            id="email"
            name="email" // Ajout de l'attribut name pour l'accessibilité
            autoComplete="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
        </div>
        <div className="form-group">
          <label htmlFor="password">Mot de passe</label>
          <input
            type="password"
            id="password"
            name="password"
            autoComplete="current-password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
        </div>
        <div className="form-options">
          <div className="form-remember">
            <input
              type="checkbox"
              id="rememberMe"
              name="rememberMe"
              checked={rememberMe}
              onChange={(e) => setRememberMe(e.target.checked)}
            />
            <label htmlFor="rememberMe">Se souvenir de moi</label>
          </div>
          <a href="/forgot-password" className="forgot-password">
            Mot de passe oublié ?
          </a>
        </div>
        <button type="submit" className="login-button">Se connecter</button>
      </form>
    </div>
  );
};

export default LoginForm;
